char *url_encode(char *str) {
    char *buf, *pbuf;

    pbuf = buf = mallocz(strlen(str) * 3 + 1);

    while (*str) {
        unsigned char c = (unsigned char)*str;

        if (isalnum(c) || c == '-' || c == '_' || c == '.' || c == '~')
            *pbuf++ = (char)c;

        else if (c == ' ')
            *pbuf++ = '+';

        else
            *pbuf++ = '%', *pbuf++ = to_hex(c >> 4), *pbuf++ = to_hex(c & 15);

        str++;
    }
    *pbuf = '\0';

    pbuf = strdupz(buf);
    freez(buf);
    return pbuf;
