void getTransportDescription( const tport_t* tp, string& desc ) {
    if( tp ) {
        const tp_name_t* tn = tport_name(tp) ;
        char name[255] ;
        /* use snprintf to avoid buffer overflow if TPN_FORMAT expands beyond buffer */
